mapper.select:
SELECT u.*, d.dept_name as deptName, r.role_name as roleName, null as lastLoginTime FROM sys_user u LEFT JOIN sys_dept d ON u.dept_id = d.id LEFT JOIN sys_user_role ur ON u.id = ur.user_id LEFT JOIN sys_role r ON ur.role_id = r.id WHERE u.is_deleted = 0
AND u.username LIKE CONCAT('%', #{request.username}, '%')
AND u.real_name LIKE CONCAT('%', #{request.name}, '%')
AND u.dept_id = #{request.departmentId}
AND u.status = #{request.status}
GROUP BY u.id ORDER BY u.create_time DESC
